    //      - if >= 2: err(EditError::MultipleMatches { count: count as u32 })
    //   7. If old_str == new_str: return Ok(serde_json::to_value(EditOutput { replaced: true })...). No write.
    //   8. Otherwise: build new content via content.replacen(old_str, new_str, 1).
    //   9. Atomic rename write:
    //      - write the new content to `{resolved}.tmp` via tokio::fs::write
    //      - tokio::fs::rename(`{resolved}.tmp`, resolved)
    //      - on io err in either step: err(EditError::IoError { reason: ... })
    //  10. Return Ok(serde_json::to_value(EditOutput { replaced: true })...).
}
```

### 2. Path resolution helper

Inline in the module (NOT cross-tool shared yet — share later if needed):

```rust
use std::path::{Path, PathBuf};

fn resolve_path(input: &str) -> Result<PathBuf, ToolError> {
    if input.is_empty() {
        return Err(err(EditError::InvalidPath { reason: "path is empty".to_string() }));
    }
    let p = Path::new(input);
    let resolved = if p.is_absolute() {
        p.to_path_buf()
    } else {
        let cwd = std::env::current_dir()
            .map_err(|e| err(EditError::InvalidPath { reason: format!("cwd: {e}") }))?;
        cwd.join(p)
    };
    Ok(resolved)
}
```

Use this at step 2 of `call`.

